mapper.delete:
		/*
             SQL ID : TkexamAnswShtDAO.userListTkexamAnswShtDelete
             설  명  : 사용자목록시험응시답안삭제
         */

	         DELETE FROM TB_LMS_TKEXAM_ANSW_SHT
	          WHERE USER_ID = #{item.userId}
	            AND EXAMPPR_ID IN (
	            	SELECT
	            		EXAMPPR.EXAMPPR_ID
			          FROM TB_LMS_EXAMPPR EXAMPPR
			          JOIN TB_LMS_TKEXAM TKEXAM
			            ON EXAMPPR.TKEXAM_ID = TKEXAM.TKEXAM_ID
			         WHERE TKEXAM.EXAM_DTL_ID = #{item.examDtlId}
			           AND TKEXAM.USER_ID = #{item.userId}
			           AND TKEXAM.DELYN = 'N'
			        )

mapper.update:
		/*
             SQL ID : TkexamAnswShtDAO.userTkexamAnswShtDelete
             설  명  : 사용자시험응시답안삭제
         */
        DELETE FROM TB_LMS_TKEXAM_ANSW_SHT
	     WHERE USER_ID = #{userId}
	       AND EXAMPPR_ID IN (
		    	SELECT
		    		EXAMPPR_ID
			      FROM TB_LMS_EXAMPPR
			     WHERE TKEXAM_ID = #{tkexamId}
			       AND USER_ID = #{userId}
		    )

/* SQL ID : TkexamAnswShtDAO.tkexamAnswShtScrModify 설 명 : 시험응시답안점수수정 */ MERGE INTO TB_LMS_TKEXAM_ANSW_SHT ANSW_SHT USING (
SELECT #{item.tkexamAnswShtId} AS TKEXAM_ANSW_SHT_ID , #{item.exampprId} AS EXAMPPR_ID , #{item.qstnId} AS QSTN_ID , #{item.userId} AS USER_ID , TO_NUMBER(#{item.scr}) AS SCR , #{item.rgtrId} AS RGTR_ID FROM DUAL
) SCR ON ( ANSW_SHT.TKEXAM_ANSW_SHT_ID = SCR.TKEXAM_ANSW_SHT_ID AND ANSW_SHT.EXAMPPR_ID = SCR.EXAMPPR_ID AND ANSW_SHT.QSTN_ID = SCR.QSTN_ID AND ANSW_SHT.USER_ID = SCR.USER_ID ) WHEN MATCHED THEN UPDATE SET ANSW_SHT.SCR = SCR.SCR , ANSW_SHT.MDFR_ID = SCR.RGTR_ID , ANSW_SHT.MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT ( TKEXAM_ANSW_SHT_ID , EXAMPPR_ID , QSTN_ID , USER_ID , SCR , RGTR_ID , REG_DTTM ) VALUES ( SCR.TKEXAM_ANSW_SHT_ID , SCR.EXAMPPR_ID , SCR.QSTN_ID , SCR.USER_ID , SCR.SCR , SCR.RGTR_ID , FN_DTTM() )
